fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Long {
    val MOD = 1000000007L
    for (query in queries) {
        val li = query[0]
        val ri = query[1]
        val ki = query[2]
        val vi = query[3]
        var idx = li.toInt()
        while (idx <= ri.toInt()) {
            nums[idx] = (nums[idx] * vi) % MOD
            idx += ki.toInt()
        }
    }
    var xor = 0L
    for (num in nums) {
        xor ^= num
    }
    return xor
}
